write_file {"path":"build-msvc.bat","content":"@echo off
REM Build script for LightningEngine using MSVC
REM This script builds the project using MSBuild from Visual Studio

setlocal enabledelayedexpansion

REM Detect Visual Studio installation
if exist "%ProgramFiles%\Microsoft Visual Studio\2022\Community\Common7\Tools\VsDevCmd.bat" (
    set VSDEVCMD="%ProgramFiles%\Microsoft Visual Studio\2022\Community\Common7\Tools\VsDevCmd.bat"
) else if exist "%ProgramFiles%\Microsoft Visual Studio\2022\Professional\Common7\Tools\VsDevCmd.bat" (
    set VSDEVCMD="%ProgramFiles%\Microsoft Visual Studio\2022\Professional\Common7\Tools\VsDevCmd.bat"
) else if exist "%ProgramFiles%\Microsoft Visual Studio\2022\Enterprise\Common7\Tools\VsDevCmd.bat" (
    set VSDEVCMD="%ProgramFiles%\Microsoft Visual Studio\2022\Enterprise\Common7\Tools\VsDevCmd.bat"
) else if exist "%ProgramFiles(x86)%\Microsoft Visual Studio\2022\Community\Common7\Tools\VsDevCmd.bat" (
    set VSDEVCMD="%ProgramFiles(x86)%\Microsoft Visual Studio\2022\Community\Common7\Tools\VsDevCmd.bat"
) else (
    echo ERROR: Visual Studio 2022 not found!
    echo Please install Visual Studio 2022 or modify this script to point to your VS installation.
    pause
    exit /b 1
)

REM Configuration (Debug or Release)
set CONFIG=Release
if not "%1"=="" set CONFIG=%1

REM Platform (x64 or Win32)
set PLATFORM=x64
if not "%2"=="" set PLATFORM=%2

echo ========================================
echo Building LightningEngine with MSVC
echo Configuration: %CONFIG%
echo Platform: %PLATFORM%
echo ========================================

REM Setup MSVC environment
call %VSDEVCMD% -arch=%PLATFORM%

REM Build the solution
MSBuild LightningEngine.sln /p:Configuration=%CONFIG% /p:Platform=%PLATFORM% /m

if %ERRORLEVEL% EQU 0 (
    echo.
    echo ========================================
    echo BUILD SUCCESSFUL!
    echo Executable: x64\%CONFIG%\LightningEngine.exe
    echo ========================================

    REM Copy DLLs if needed
    if exist "third_party\SDL3\lib\x64\*.dll" (
        copy "third_party\SDL3\lib\x64\*.dll" "x64\%CONFIG%\" >nul 2>&1
        echo SDL3 DLLs copied to output directory.
    )

    REM Optionally run the executable
    echo.
    echo To run the application:
    echo   x64\%CONFIG%\LightningEngine.exe
) else (
    echo.
    echo ========================================
    echo BUILD FAILED!
    echo ========================================
    exit /b %ERRORLEVEL%
)

pause
"}

